import { mergeProps } from "@base-ui/react";
import { Separator as SeparatorPrimitive } from "@base-ui/react/separator";
import * as stylex from "@stylexjs/stylex";
import type * as React from "react";
import { separatorStyles } from "./separator.styles";

type Orientation = "horizontal" | "vertical";
type SeparatorTone = "subtle" | "strong";

export type SeparatorProps = Omit<SeparatorPrimitive.Props, "style"> & {
	orientation?: Orientation;
	label?: React.ReactNode;
	tone?: SeparatorTone;
	style?: stylex.StyleXStyles;
};

export function Separator({
	orientation = "horizontal",
	label,
	tone = "strong",
	style,
	...props
}: SeparatorProps) {
	const toneStyle =
		tone === "strong" ? separatorStyles.strong : separatorStyles.subtle;
	let defaultProps = {};
	if (orientation === "horizontal" && label) {
		defaultProps = stylex.props(
			separatorStyles.base,
			separatorStyles.withLabel,
			toneStyle,
			style,
		);
	} else if (orientation === "horizontal")
		defaultProps = stylex.props(
			separatorStyles.base,
			separatorStyles.horizontal,
			toneStyle,
			style,
		);
	else
		defaultProps = stylex.props(
			separatorStyles.base,
			separatorStyles.vertical,
			toneStyle,
			style,
		);

	const mergedProps = mergeProps(props, defaultProps);
	return <SeparatorPrimitive {...mergedProps} />;
}

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import { fontSize, fontWeight, spacing } from "@/lib/theme/tokens.stylex";

export const separatorStyles = stylex.create({
	base: {
		boxSizing: "border-box",
		flexShrink: 0,
		backgroundColor: "currentColor",
	},

	horizontal: {
		flexGrow: 1,
		height: 1,
	},
	vertical: {
		width: 1,
		height: "100%",
	},

	subtle: {
		color: theme.borderSubtle,
	},
	strong: {
		color: theme.borderStrong,
	},

	withLabel: {
		backgroundColor: "transparent",
		display: "flex",
		alignItems: "center",
		gap: spacing.small,
		width: "100%",
		"::before": {
			content: '""',
			flex: 1,
			height: 1,
			backgroundColor: "currentColor",
			opacity: 1,
		},
		"::after": {
			content: '""',
			flex: 1,
			height: 1,
			backgroundColor: "currentColor",
			opacity: 1,
		},
	},

	label: {
		paddingLeft: spacing.xsmall,
		paddingRight: spacing.xsmall,
		color: theme.contentSecondary,
		fontSize: fontSize.xsmall,
		fontWeight: fontWeight.medium,
		lineHeight: 1.2,
		whiteSpace: "nowrap",
	},
});
